"""Тесты обработчика секции image_processing (ImageProcessingConfig)."""from types import SimpleNamespacefrom unittest.mock import patchfrom src.modules.project.sections.image_processing_config import (    IMAGE_PROCESSING_DEFAULTS,    IMAGE_PROCESSING_KEYS,    IMAGE_PROCESSING_LOGICS,)def test_image_processing_logics_defaults_keys() -> None:    """IMAGE_PROCESSING_LOGICS, IMAGE_PROCESSING_DEFAULTS, IMAGE_PROCESSING_KEYS доступны."""    L = IMAGE_PROCESSING_LOGICS    D = IMAGE_PROCESSING_DEFAULTS    K = IMAGE_PROCESSING_KEYS    assert L.skip == "skip"    assert L.ocr_only == "ocr_only"    assert L.vision_only == "vision_only"    assert len(L.options) == 3    assert L.valid_codes == frozenset({"skip", "ocr_only", "vision_only"})    assert D.ocr_provider == "yandex_ocr"    assert D.ocr_model == "page"    assert D.vision_provider == ""    assert D.vision_model == ""    assert D.vision_reasoning == "disabled"    assert D.vision_system_prompt == ""    assert D.vision_temperature == 0.3    assert K.image_processing_logic == "image_processing_logic"    assert K.ocr_provider == "ocr_provider"    assert K.ocr_model == "ocr_model"    assert K.vision_provider == "vision_provider"    assert K.vision_model == "vision_model"    assert K.vision_reasoning == "vision_reasoning"    assert K.vision_system_prompt == "vision_system_prompt"    assert K.vision_temperature == "vision_temperature"def test_get_default_returns_full_dict() -> None:    """Умолчание содержит все ключи секции."""    from src.modules.project.sections import ImageProcessingConfig    default = ImageProcessingConfig.get_default()    assert isinstance(default, dict)    assert default[IMAGE_PROCESSING_KEYS.image_processing_logic] == IMAGE_PROCESSING_LOGICS.skip    assert default[IMAGE_PROCESSING_KEYS.ocr_provider] == IMAGE_PROCESSING_DEFAULTS.ocr_provider    assert default[IMAGE_PROCESSING_KEYS.ocr_model] == IMAGE_PROCESSING_DEFAULTS.ocr_model    assert default[IMAGE_PROCESSING_KEYS.vision_provider] == IMAGE_PROCESSING_DEFAULTS.vision_provider    assert default[IMAGE_PROCESSING_KEYS.vision_model] == IMAGE_PROCESSING_DEFAULTS.vision_model    assert default[IMAGE_PROCESSING_KEYS.vision_reasoning] == IMAGE_PROCESSING_DEFAULTS.vision_reasoning    assert default[IMAGE_PROCESSING_KEYS.vision_system_prompt] == IMAGE_PROCESSING_DEFAULTS.vision_system_prompt    assert default[IMAGE_PROCESSING_KEYS.vision_temperature] == IMAGE_PROCESSING_DEFAULTS.vision_temperaturedef test_validate_valid_data_returns_empty_list() -> None:    """Валидные данные не дают ошибок."""    from src.modules.project.sections import ImageProcessingConfig    assert ImageProcessingConfig.validate(ImageProcessingConfig.get_default()) == []    assert ImageProcessingConfig.validate({        IMAGE_PROCESSING_KEYS.image_processing_logic: IMAGE_PROCESSING_LOGICS.ocr_only,        IMAGE_PROCESSING_KEYS.ocr_provider: IMAGE_PROCESSING_DEFAULTS.ocr_provider,        IMAGE_PROCESSING_KEYS.ocr_model: IMAGE_PROCESSING_DEFAULTS.ocr_model,        IMAGE_PROCESSING_KEYS.vision_provider: "",        IMAGE_PROCESSING_KEYS.vision_model: "",    }) == []def test_validate_non_dict_returns_error() -> None:    """Не-словарь даёт ошибку."""    from src.modules.project.sections import ImageProcessingConfig    errors = ImageProcessingConfig.validate(None)    assert len(errors) == 1    assert "объект" in errors[0] or "dict" in errors[0]def test_validate_invalid_logic_returns_error() -> None:    """Недопустимый image_processing_logic даёт ошибку."""    from src.modules.project.sections import ImageProcessingConfig    errors = ImageProcessingConfig.validate({"image_processing_logic": "invalid_mode"})    assert len(errors) == 1    assert "image_processing_logic" in errors[0]    assert "skip" in errors[0] or "ocr_only" in errors[0]def test_validate_non_string_field_returns_error() -> None:    """Поле провайдера/модели не строкового типа даёт ошибку."""    from src.modules.project.sections import ImageProcessingConfig    errors = ImageProcessingConfig.validate({        IMAGE_PROCESSING_KEYS.image_processing_logic: IMAGE_PROCESSING_LOGICS.skip,        IMAGE_PROCESSING_KEYS.ocr_provider: 123,    })    assert len(errors) >= 1    assert any("ocr_provider" in e or "строкой" in e for e in errors)def test_validate_invalid_vision_reasoning_returns_error() -> None:    """Недопустимый vision_reasoning даёт ошибку."""    from src.modules.project.sections import ImageProcessingConfig    errors = ImageProcessingConfig.validate({        IMAGE_PROCESSING_KEYS.image_processing_logic: IMAGE_PROCESSING_LOGICS.vision_only,        IMAGE_PROCESSING_KEYS.vision_reasoning: "invalid",    })    assert len(errors) >= 1    assert any("vision_reasoning" in e or "disabled" in e for e in errors)def test_validate_invalid_vision_temperature_returns_error() -> None:    """Температура вне 0.0–2.0 или не число даёт ошибку."""    from src.modules.project.sections import ImageProcessingConfig    errors = ImageProcessingConfig.validate({        IMAGE_PROCESSING_KEYS.image_processing_logic: IMAGE_PROCESSING_LOGICS.vision_only,        IMAGE_PROCESSING_KEYS.vision_temperature: 3.0,    })    assert len(errors) >= 1    assert any("vision_temperature" in e or "0.0" in e for e in errors)    errors2 = ImageProcessingConfig.validate({        IMAGE_PROCESSING_KEYS.image_processing_logic: IMAGE_PROCESSING_LOGICS.vision_only,        IMAGE_PROCESSING_KEYS.vision_temperature: "x",    })    assert len(errors2) >= 1    assert any("vision_temperature" in e for e in errors2)@patch("src.modules.project.sections.image_processing_config.AppConfigStore.get")@patch("src.modules.llm_models_registry.LLMModelManager")def test_get_available_values_vision_only_input_image_models(    mock_manager_class: object,    mock_app_config_get: object,) -> None:    """Vision-провайдеры и модели только с input_image: провайдер без таких моделей не выбирается."""    from src.modules.project.sections import ImageProcessingConfig    # Провайдеры с ключами: все доступны    mock_lp = SimpleNamespace(is_provider_available=lambda _: True)    mock_yo = SimpleNamespace(is_available=lambda: False)    mock_core = SimpleNamespace(debug=False)    mock_app_config_get.return_value = SimpleNamespace(        llm_providers=mock_lp,        yandex_ocr=mock_yo,        core=mock_core,    )    # Реестр: openai — одна модель с input_image; anthropic — только без input_image; xai — пусто    mock_manager = mock_manager_class.return_value    mock_manager.get_sorted_records.return_value = [        {"provider": "openai", "name": "gpt-4o", "enabled": True, "input_image": True},        {"provider": "openai", "name": "gpt-3.5", "enabled": True, "input_image": False},        {"provider": "anthropic", "name": "claude-3", "enabled": True, "input_image": False},    ]    state = ImageProcessingConfig.get_available_values()    assert state.vision_providers == ["openai"]    assert state.vision_models == {"openai": ["gpt-4o"]}    assert "anthropic" not in state.vision_providers    assert "xai" not in state.vision_providers